package ir.tahamohamadi.skill; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*;
@Entity @Table(name="skill") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class Skill extends AuditedSoftDeletableEntity { @Column(name="skill_key",nullable=false) private String skillKey; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="skill_category_id",nullable=false) private SkillCategory category; @Column(name="sort_order",nullable=false) private int sortOrder; @Column(name="is_active",nullable=false) private boolean active; }
